import React from 'react';
import { ROOM_TYPES } from '../data/bookingData.js';
import styles from '../styles/RoomSelector.module.css';

const INCLUSIONS = [
  { icon: '🏡', label: 'Exclusive resort use' },
  { icon: '🛏️', label: 'Villa rooms' },
  { icon: '📶', label: 'Wi-Fi' },
  { icon: '🍳', label: 'Restaurant kitchen' },
  { icon: '🚿', label: '2 showers & 3 bathrooms' },
  { icon: '🌡️', label: 'Hot & cold showers' },
  { icon: '💧', label: 'Water dispenser (3 free gallons)' },
  { icon: '📺', label: 'TV & speaker' },
  { icon: '🔥', label: 'Bonfire setup (2 sacks firewood)' },
  { icon: '⚡', label: 'Generator set standby' },
  { icon: '🚗', label: 'Gated parking (10–12 cars)' },
  { icon: '🏞️', label: 'Direct river access' },
];

const RoomCard = ({ room, selected, onClick }) => (
  <button
    className={`${styles.card} ${selected ? styles.selected : ''}`}
    onClick={() => onClick(room)}
    type="button"
  >
    <div className={styles.icon}>{room.icon}</div>
    <div className={styles.info}>
      <h3 className={styles.name}>{room.name}</h3>
      <p className={styles.desc}>{room.description}</p>
      <p className={styles.guests}>Up to {room.maxGuests} guests</p>
    </div>
    <div className={styles.price}>
      <span className={styles.amount}>₱{room.price.toLocaleString()}</span>
      <span className={styles.per}>/ night</span>
    </div>
    {selected && <div className={styles.checkMark}>✓</div>}
  </button>
);

const RoomSelector = ({ selectedRoom, onSelect }) => (
  <section className={styles.section}>
    <div className={styles.sectionLabel}>
      <span className={styles.labelLine} />
      <span className={styles.labelText}>Choose Your Room</span>
      <span className={styles.labelLine} />
    </div>
    <div className={styles.grid}>
      {ROOM_TYPES.map((room) => (
        <RoomCard
          key={room.id}
          room={room}
          selected={selectedRoom?.id === room.id}
          onClick={onSelect}
        />
      ))}
    </div>

    <div className={styles.inclusionsBlock}>
      <div className={styles.sectionLabel} style={{ marginTop: '32px' }}>
        <span className={styles.labelLine} />
        <span className={styles.labelText}>Inclusions</span>
        <span className={styles.labelLine} />
      </div>
      <div className={styles.inclusionsGrid}>
        {INCLUSIONS.map((item) => (
          <div key={item.label} className={styles.inclusionItem}>
            <span className={styles.inclusionIcon}>{item.icon}</span>
            <span className={styles.inclusionLabel}>{item.label}</span>
          </div>
        ))}
      </div>
    </div>
  </section>
);

export default RoomSelector;
